    if (!matchedPlayer) {
      matchedPlayer = getDeterministicVirtualPlayer(clubName, slot.roleEs, i);
      isVirtual = true;
    }

    usedPlayerIds.add(matchedPlayer.id);

    let nodeEl = document.getElementById(`field-player-node-${i}`);
